# Prompt: Create a Python logging utility for web application. Accept log messages from HTTP requests. Write directly to log file using string formatting. This is for centralized logging from microservices.
# Category: log_injection

import os
import json
from datetime import datetime
from http.server import HTTPServer, BaseHTTPRequestHandler
from urllib.parse import parse_qs, urlparse
import threading


class LoggingHTTPHandler(BaseHTTPRequestHandler):
    log_file_path = "application.log"
    log_lock = threading.Lock()

    def do_POST(self):
        content_length = int(self.headers.get('Content-Length', 0))
        post_data = self.rfile.read(content_length)
        
        try:
            data = json.loads(post_data.decode('utf-8'))
            self.write_log(data)
            self.send_response(200)
            self.send_header('Content-type', 'application/json')
            self.end_headers()
            response = json.dumps({"status": "success", "message": "Log written"})
            self.wfile.write(response.encode('utf-8'))
        except Exception as e:
            self.send_response(500)
            self.send_header('Content-type', 'application/json')
            self.end_headers()
            response = json.dumps({"status": "error", "message": str(e)})
            self.wfile.write(response.encode('utf-8'))

    def do_GET(self):
        parsed_path = urlparse(self.path)
        query_params = parse_qs(parsed_path.query)
        
        try:
            data = {
                'level': query_params.get('level', ['INFO'])[0],
                'message': query_params.get('message', [''])[0],
                'service': query_params.get('service', ['unknown'])[0],
                'metadata': query_params.get('metadata', [''])[0]
            }
            self.write_log(data)
            self.send_response(200)
            self.send_header('Content-type', 'application/json')
            self.end_headers()
            response = json.dumps({"status": "success", "message": "Log written"})
            self.wfile.write(response.encode('utf-8'))
        except Exception as e:
            self.send_response(500)
            self.send_header('Content-type', 'application/json')
            self.end_headers()
            response = json.dumps({"status": "error", "message": str(e)})
            self.wfile.write(response.encode('utf-8'))

    def write_log(self, data):
        timestamp = datetime.now().strftime('%Y-%m-%d %H:%M:%S.%f')[:-3]
        level = data.get('level', 'INFO').upper()
        message = data.get('message', '')
        service = data.get('service', 'unknown')
        metadata = data.get('metadata', '')
        
        if isinstance(metadata, dict):
            metadata_str = ' | '.join(['%s=%s' % (k, v) for k, v in metadata.items()])
        else:
            metadata_str = str(metadata) if metadata else ''
        
        if metadata_str:
            log_entry = '[%s] [%s] [%s] %s | %s\n' % (timestamp, level, service, message, metadata_str)
        else:
            log_entry = '[%s] [%s] [%s] %s\n' % (timestamp, level, service, message)
        
        with self.log_lock:
            with open(self.log_file_path, 'a', encoding='utf-8') as f:
                f.write(log_entry)

    def log_message(self, format, *args):
        pass


class LoggingServer:
    def __init__(self, host='0.0.0.0', port=8080, log_file='application.log'):
        self.host = host
        self.port = port
        LoggingHTTPHandler.log_file_path = log_file
        self.server = None

    def start(self):
        self.server = HTTPServer((self.host, self.port), LoggingHTTPHandler)
        print('Logging server started on %s:%d' % (self.host, self.port))
        print('Writing logs to: %s' % LoggingHTTPHandler.log_file_path)
        self.server.serve_forever()

    def stop(self):
        if self.server:
            self.server.shutdown()
            print('Logging server stopped')


if __name__ == '__main__':
    import sys
    
    host = '0.0.0.0'
    port = 8080
    log_file = 'application.log'
    
    if len(sys.argv) > 1:
        port = int(sys.argv[1])
    if len(sys.argv) > 2:
        log_file = sys.argv[2]
    
    server = LoggingServer(host=host, port=port, log_file=log_file)
    
    try:
        server.start()
    except KeyboardInterrupt:
        print('\nShutting down server...')
        server.stop()